use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from a PDF file
sub extract_text {
    my ($filename, $search_key) = @_;

    # Create a new PDF object
    my $pdf = PDF::API2->open($filename);

    # Extract text from the PDF
    my $text = PDF::Text::Simple->new($pdf);

    my @content;
    while (my $page = $text->next_page) {
        @content = () unless @content;
        $page =~ s/[\n\r]+/ /g;
        push @content, $page;
    }

    # Join all content into a single string
    my $full_text = join("", @content);

    # Search for the specific text
    if (defined $search_key) {
        if ($full_text =~ /$search_key/) {
            return $1;
        } else {
            return "No match found for $search_key in the PDF.";
        }
    } else {
        return $full_text;
    }
}

